mapper.select:
SELECT COUNT(1) AS diagnosisTotal, COALESCE(SUM(CASE WHEN COALESCE(r.report_status, 1) = 1 THEN 1 ELSE 0 END), 0) AS pendingAuditCount, COALESCE(SUM(CASE WHEN COALESCE(r.report_status, 1) = 2 THEN 1 ELSE 0 END), 0) AS auditedPassCount, COALESCE(SUM(CASE WHEN a.is_abnormal = 1 THEN 1 ELSE 0 END), 0) AS abnormalCount, COALESCE(SUM(CASE WHEN a.is_abnormal = 0 THEN 1 ELSE 0 END), 0) AS normalCount FROM ecg_ai_diagnosis a LEFT JOIN ecg_diagnosis_report r ON r.report_id = ( SELECT rr.report_id FROM ecg_diagnosis_report rr WHERE rr.ai_diagnosis_id = a.ai_diagnosis_id AND rr.is_deleted = 0 ORDER BY rr.report_create_time DESC, rr.report_id DESC LIMIT 1 ) WHERE a.is_deleted = 0 AND a.analysis_status = 2
AND COALESCE(a.diagnosis_time, a.analysis_end_time, a.analysis_start_time) >= #{startTime}
AND COALESCE(a.diagnosis_time, a.analysis_end_time, a.analysis_start_time) < #{endTime}

SELECT COALESCE(NULLIF(a.abnormal_type, ''), '其他异常') AS abnormalType, COUNT(1) AS count, 0 AS ratio FROM ecg_ai_diagnosis a WHERE a.is_deleted = 0 AND a.analysis_status = 2 AND a.is_abnormal = 1 AND COALESCE(a.abnormal_count, 0) > 0
AND COALESCE(a.diagnosis_time, a.analysis_end_time, a.analysis_start_time) >= #{startTime}
AND COALESCE(a.diagnosis_time, a.analysis_end_time, a.analysis_start_time) < #{endTime}
GROUP BY COALESCE(NULLIF(a.abnormal_type, ''), '其他异常') ORDER BY count DESC LIMIT 10

SELECT a.diagnosis_no AS diagnosisId, a.ai_diagnosis_id AS aiDiagnosisId, a.record_id AS ecgId, a.ecg_no AS ecgNo, a.patient_name AS patientName, a.gender AS gender, a.age AS age, a.inpatient_no AS inpatientNo, a.dept_id AS deptId, a.dept_name AS deptName, COALESCE(NULLIF(a.ai_conclusion, ''), '-') AS aiConclusion, COALESCE(NULLIF(a.abnormal_type, ''), '-') AS abnormalType, COALESCE(a.abnormal_count, 0) AS abnormalCount, COALESCE(a.confidence, 0) AS confidence, COALESCE(r.report_status, 1) AS reportStatus, CASE WHEN COALESCE(r.report_status, 1) = 1 THEN '待审核' WHEN COALESCE(r.report_status, 1) = 2 THEN '审核通过' WHEN COALESCE(r.report_status, 1) = 3 THEN '已驳回' WHEN COALESCE(r.report_status, 1) = 4 THEN '已作废' ELSE '待审核' END AS reportStatusText, ws.warning_level AS warningLevel, CASE WHEN ws.warning_level = 1 THEN '低危' WHEN ws.warning_level = 2 THEN '中危' WHEN ws.warning_level = 3 THEN '高危' ELSE '正常' END AS warningLevelText, COALESCE(a.diagnosis_time, a.analysis_end_time, a.analysis_start_time) AS diagnosisTime FROM ecg_ai_diagnosis a LEFT JOIN ecg_diagnosis_report r ON r.report_id = ( SELECT rr.report_id FROM ecg_diagnosis_report rr WHERE rr.ai_diagnosis_id = a.ai_diagnosis_id AND rr.is_deleted = 0 ORDER BY rr.report_create_time DESC, rr.report_id DESC LIMIT 1 ) LEFT JOIN ( SELECT COALESCE(ww.ai_diagnosis_id, -1) AS ai_diagnosis_id_key, ww.record_id, MAX(ww.warning_level) AS warning_level FROM ecg_abnormal_warning ww WHERE ww.is_deleted = 0 GROUP BY COALESCE(ww.ai_diagnosis_id, -1), ww.record_id ) ws ON ws.record_id = a.record_id AND ws.ai_diagnosis_id_key = COALESCE(a.ai_diagnosis_id, -1) WHERE a.is_deleted = 0 AND a.analysis_status = 2
AND ( a.ecg_no LIKE CONCAT('%', #{req.keyword}, '%') OR a.patient_name LIKE CONCAT('%', #{req.keyword}, '%') OR a.inpatient_no LIKE CONCAT('%', #{req.keyword}, '%') OR a.diagnosis_no LIKE CONCAT('%', #{req.keyword}, '%') )
AND a.dept_id = #{req.deptId}
AND COALESCE(a.diagnosis_time, a.analysis_end_time, a.analysis_start_time) >= #{startTime}
AND COALESCE(a.diagnosis_time, a.analysis_end_time, a.analysis_start_time) < #{endTime}
ORDER BY COALESCE(a.diagnosis_time, a.analysis_end_time, a.analysis_start_time) DESC, a.ai_diagnosis_id DESC

SELECT w.warning_id AS warningId, w.warning_type AS warningType, w.warning_level AS warningLevel, CASE WHEN w.warning_level = 1 THEN '低危' WHEN w.warning_level = 2 THEN '中危' WHEN w.warning_level = 3 THEN '高危' ELSE '未知' END AS warningLevelText, w.handle_status AS handleStatus, CASE WHEN w.handle_status = 0 THEN '待确认' WHEN w.handle_status = 1 THEN '待处理' WHEN w.handle_status = 2 THEN '处理中' WHEN w.handle_status = 3 THEN '已处理' WHEN w.handle_status = 4 THEN '已忽略' ELSE '待确认' END AS handleStatusText, w.warning_time AS warningTime, w.warning_desc AS warningDesc, w.handle_opinion AS handleOpinion FROM ecg_abnormal_warning w WHERE w.is_deleted = 0
AND w.ai_diagnosis_id = #{aiDiagnosisId}
AND w.record_id = #{recordId}
ORDER BY w.warning_time DESC, w.warning_id DESC
